import { Select } from '@/components/select';
import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import ChevronLeft from 'lucide-solid/icons/chevron-left';
import ChevronRight from 'lucide-solid/icons/chevron-right';
import {
  Component,
  createEffect,
  createMemo,
  createSignal,
  For,
  Match,
  mergeProps,
  Show,
  Switch,
} from 'solid-js';
import type {
  PaginationDefaultProps,
  PaginationFullyProps,
  PaginationProps,
  PaginationSimpleProps,
} from './pagination.types';

const DEFAULT_PROPS = {
  defaultCurrent: 1,
  defaultPageSize: 10,
  total: 0,
  align: 'start' as const,
  size: 'md' as const,
  color: 'neutral' as const,
  hideOnSinglePage: false,
  showLessItems: false,
  showQuickJumper: false,
  showTitle: true,
  disabled: false,
  pageSizeOptions: [10, 20, 50, 100],
  totalBoundaryShowSizeChanger: 50,
};

// ─── Shared helpers ─────────────────────────────────────────────────────────

function buildSizeClass(size: string) {
  switch (size) {
    case 'xs':
      return 'pag26';
    case 'sm':
      return 'pag27';
    case 'lg':
      return 'pag29';
    case 'xl':
      return 'pag30';
    default:
      return 'pag28';
  }
}

function buildAlignClass(align: string) {
  switch (align) {
    case 'center':
      return 'justify-center';
    case 'end':
      return 'justify-end';
    default:
      return 'justify-start';
  }
}

function mapSizeToSelect(size: string): 'sm' | 'md' | 'lg' {
  if (size === 'lg' || size === 'xl') return 'lg';
  if (size === 'md') return 'md';
  return 'sm';
}

// Build page list with ellipsis algorithm
function buildPageItems(totalPages: number, current: number, showLessItems: boolean) {
  const sibling = showLessItems ? 1 : 2;

  if (totalPages <= (showLessItems ? 7 : 9)) {
    return Array.from({ length: totalPages }, (_, i) => i + 1);
  }

  const items: (number | 'prev-ellipsis' | 'next-ellipsis')[] = [];

  items.push(1);

  const leftBound = Math.max(2, current - sibling);
  const rightBound = Math.min(totalPages - 1, current + sibling);

  if (leftBound > 2) items.push('prev-ellipsis');
  for (let i = leftBound; i <= rightBound; i++) items.push(i);
  if (rightBound < totalPages - 1) items.push('next-ellipsis');

  items.push(totalPages);

  return items;
}

// ─── Mode: default ──────────────────────────────────────────────────────────

const PaginationDefault: Component<PaginationDefaultProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);

  const [internalCurrent, setInternalCurrent] = createSignal(p.defaultCurrent);
  const [internalPageSize, setInternalPageSize] = createSignal(p.defaultPageSize);
  const [jumpValue, setJumpValue] = createSignal('');

  const current = createMemo(() => p.current ?? internalCurrent());
  const pageSize = createMemo(() => p.pageSize ?? internalPageSize());
  const totalPages = createMemo(() => Math.max(1, Math.ceil((p.total ?? 0) / pageSize())));

  const showSizeChanger = createMemo(() => {
    if (typeof p.showSizeChanger === 'boolean') return p.showSizeChanger;
    if (typeof p.showSizeChanger === 'object') return true;
    return (p.total ?? 0) > (p.totalBoundaryShowSizeChanger ?? 50);
  });

  const shouldHide = createMemo(() => p.hideOnSinglePage && totalPages() <= 1);

  const changePage = (page: number) => {
    const clamped = Math.min(Math.max(1, page), totalPages());
    if (clamped === current()) return;
    setInternalCurrent(clamped);
    p.onChange?.(clamped, pageSize());
  };

  const changePageSize = (size: number) => {
    const newTotal = Math.max(1, Math.ceil((p.total ?? 0) / size));
    const newCurrent = Math.min(current(), newTotal);
    setInternalPageSize(size);
    setInternalCurrent(newCurrent);
    p.onShowSizeChange?.(newCurrent, size);
    p.onChange?.(newCurrent, size);
  };

  const pageItems = createMemo(() => buildPageItems(totalPages(), current(), p.showLessItems));

  const handleJump = () => {
    const val = parseInt(jumpValue(), 10);
    if (!isNaN(val)) {
      changePage(val);
      setJumpValue('');
    }
  };

  const range = createMemo<[number, number]>(() => {
    const start = (current() - 1) * pageSize() + 1;
    const end = Math.min(current() * pageSize(), p.total ?? 0);
    return [start, end];
  });

  const pageSizeSelectOpts = createMemo(() =>
    p.pageSizeOptions.map(opt => ({ label: `${opt} / page`, value: opt as number })),
  );

  return (
    <Show when={!shouldHide()}>
      <div
        class={cn(
          'pag01 pag02',
          buildSizeClass(p.size),
          buildAlignClass(p.align),
          getColor(p.color),
          p.disabled && 'pag05',
          p.class?.root,
        )}
      >
        {/* Show total */}
        <Show when={p.showTotal}>
          <span class={cn('pag13', p.class?.total)}>{p.showTotal!(p.total ?? 0, range())}</span>
        </Show>

        {/* Prev button */}
        {(() => {
          const btn = (
            <button
              class={cn(
                'pag06 pag08',
                p.class?.btn,
                p.class?.prev,
                current() <= 1 && 'pag07',
                current() <= 1 && p.class?.btnDisabled,
              )}
              disabled={p.disabled || current() <= 1}
              onClick={() => changePage(current() - 1)}
              title="Previous Page"
            >
              <ChevronLeft size={16} />
            </button>
          );
          return p.itemRender ? p.itemRender(current() - 1, 'prev', btn) : btn;
        })()}

        {/* Page items */}
        <For each={pageItems()}>
          {item => {
            if (item === 'prev-ellipsis' || item === 'next-ellipsis') {
              return (
                <button
                  class={cn('pag06 pag10', p.class?.btn, p.class?.ellipsis)}
                  disabled={p.disabled}
                  onClick={() => {
                    const jump =
                      item === 'prev-ellipsis'
                        ? Math.max(1, current() - (p.showLessItems ? 3 : 5))
                        : Math.min(totalPages(), current() + (p.showLessItems ? 3 : 5));
                    changePage(jump);
                  }}
                  title={item === 'prev-ellipsis' ? 'Previous 5 pages' : 'Next 5 pages'}
                >
                  •••
                </button>
              );
            }
            const pageBtn = (
              <button
                class={cn(
                  'pag06',
                  item === current() && 'pag11',
                  item === current() && p.class?.itemActive,
                  p.class?.btn,
                )}
                disabled={p.disabled}
                onClick={() => changePage(item)}
                title={p.showTitle ? `Page ${item}` : undefined}
              >
                {item}
              </button>
            );
            return p.itemRender ? p.itemRender(item, 'page', pageBtn) : pageBtn;
          }}
        </For>

        {/* Next button */}
        {(() => {
          const btn = (
            <button
              class={cn(
                'pag06 pag09',
                current() >= totalPages() && 'pag07',
                current() >= totalPages() && p.class?.btnDisabled,
                p.class?.btn,
                p.class?.next,
              )}
              disabled={p.disabled || current() >= totalPages()}
              onClick={() => changePage(current() + 1)}
              title="Next Page"
            >
              <ChevronRight size={16} />
            </button>
          );
          return p.itemRender ? p.itemRender(current() + 1, 'next', btn) : btn;
        })()}

        {/* Size changer */}
        <Show when={showSizeChanger()}>
          <div class="w-fit">
            <Select
              options={pageSizeSelectOpts()}
              value={pageSize()}
              onChange={val => changePageSize(val as number)}
              disabled={p.disabled}
              size={mapSizeToSelect(p.size)}
              color={p.color}
              placement="top"
              class={{ root: p.class?.sizeChanger }}
            />
          </div>
        </Show>

        {/* Quick jumper */}
        <Show when={p.showQuickJumper}>
          <span
            class={cn(
              'pag14',
              p.align === 'end' && 'order-first mr-auto',
              p.align === 'start' && 'ml-auto',
              p.class?.jumper,
            )}
          >
            <span class={cn('pag15', p.class?.jumperLabel)}>Go to</span>
            <input
              class={cn('pag16', p.class?.jumperInput)}
              type="number"
              min={1}
              max={totalPages()}
              value={jumpValue()}
              disabled={p.disabled}
              onInput={e => setJumpValue(e.currentTarget.value)}
              onKeyDown={e => {
                if (e.key === 'Enter') {
                  handleJump();
                  e.currentTarget.blur();
                }
              }}
            />
            <Show
              when={typeof p.showQuickJumper === 'object' && p.showQuickJumper.goButton}
              fallback={null}
            >
              <span onClick={() => handleJump()} class="cursor-pointer">
                {(p.showQuickJumper as { goButton: any }).goButton}
              </span>
            </Show>
          </span>
        </Show>
      </div>
    </Show>
  );
};

// ─── Mode: simple ────────────────────────────────────────────────────────────

const PaginationSimple: Component<PaginationSimpleProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);

  const [internalCurrent, setInternalCurrent] = createSignal(p.defaultCurrent);
  const [internalPageSize, setInternalPageSize] = createSignal(p.defaultPageSize);

  const current = createMemo(() => p.current ?? internalCurrent());
  const pageSize = createMemo(() => p.pageSize ?? internalPageSize());
  const totalPages = createMemo(() => Math.max(1, Math.ceil((p.total ?? 0) / pageSize())));
  const shouldHide = createMemo(() => p.hideOnSinglePage && totalPages() <= 1);

  const changePage = (page: number) => {
    const clamped = Math.min(Math.max(1, page), totalPages());
    if (clamped === current()) return;
    setInternalCurrent(clamped);
    p.onChange?.(clamped, pageSize());
  };

  return (
    <Show when={!shouldHide()}>
      <div
        class={cn(
          'pag01 pag03',
          buildSizeClass(p.size),
          buildAlignClass(p.align),
          getColor(p.color),
          p.disabled && 'pag05',
          p.class?.root,
        )}
      >
        <button
          class={cn(
            'pag06 pag08',
            p.class?.btn,
            p.class?.prev,
            current() <= 1 && 'pag07',
            current() <= 1 && p.class?.btnDisabled,
          )}
          disabled={p.disabled || current() <= 1}
          onClick={() => changePage(current() - 1)}
          title="Previous"
        >
          <ChevronLeft size={16} />
        </button>
        <span class={cn('pag17', p.class?.simplePager)}>
          <input
            class={cn('pag18', p.class?.simpleInput)}
            type="number"
            min={1}
            max={totalPages()}
            value={current()}
            disabled={p.disabled}
            onFocus={e => e.currentTarget.select()}
            onKeyDown={e => {
              if (e.key === 'Enter') {
                const v = parseInt((e.target as HTMLInputElement).value, 10);
                if (!isNaN(v)) changePage(v);
              }
            }}
            onBlur={e => {
              const v = parseInt(e.currentTarget.value, 10);
              if (!isNaN(v)) changePage(v);
            }}
          />
          <span class={cn('pag19', p.class?.slash)}>/</span>
          <span>{totalPages()}</span>
        </span>
        <button
          class={cn(
            'pag06 pag09',
            p.class?.btn,
            p.class?.next,
            current() >= totalPages() && 'pag07',
            current() >= totalPages() && p.class?.btnDisabled,
          )}
          disabled={p.disabled || current() >= totalPages()}
          onClick={() => changePage(current() + 1)}
          title="Next"
        >
          <ChevronRight size={16} />
        </button>
      </div>
    </Show>
  );
};

// ─── Mode: fully ─────────────────────────────────────────────────────────────

const PaginationFully: Component<PaginationFullyProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);

  const [internalCurrent, setInternalCurrent] = createSignal(p.defaultCurrent);
  const [internalPageSize, setInternalPageSize] = createSignal(p.defaultPageSize);
  const [modernPageInput, setModernPageInput] = createSignal(String(p.defaultCurrent ?? 1));

  const current = createMemo(() => p.current ?? internalCurrent());
  const pageSize = createMemo(() => p.pageSize ?? internalPageSize());
  const totalPages = createMemo(() => Math.max(1, Math.ceil((p.total ?? 0) / pageSize())));
  const shouldHide = createMemo(() => p.hideOnSinglePage && totalPages() <= 1);

  createEffect(function syncPageInput() {
    setModernPageInput(String(current()));
  });

  const changePage = (page: number) => {
    const clamped = Math.min(Math.max(1, page), totalPages());
    if (clamped === current()) return;
    setInternalCurrent(clamped);
    p.onChange?.(clamped, pageSize());
  };

  const changePageSize = (size: number) => {
    const newTotal = Math.max(1, Math.ceil((p.total ?? 0) / size));
    const newCurrent = Math.min(current(), newTotal);
    setInternalPageSize(size);
    setInternalCurrent(newCurrent);
    p.onShowSizeChange?.(newCurrent, size);
    p.onChange?.(newCurrent, size);
  };

  const range = createMemo<[number, number]>(() => {
    const start = (current() - 1) * pageSize() + 1;
    const end = Math.min(current() * pageSize(), p.total ?? 0);
    return [start, end];
  });

  const commitPageInput = (value: string) => {
    const num = parseInt(value, 10);
    const clamped = !isNaN(num) ? Math.min(Math.max(1, num), totalPages()) : current();
    changePage(clamped);
    setModernPageInput(String(clamped));
  };

  return (
    <Show when={!shouldHide()}>
      <div
        class={cn(
          'pag01 pag04',
          buildSizeClass(p.size),
          getColor(p.color),
          p.disabled && 'pag05',
          p.class?.root,
        )}
      >
        {/* Left: items-per-page dropdown + range */}
        <div class={cn('pag20', p.class?.fullyLeft)}>
          <span class={cn('pag22', p.class?.fullyLabel)}>Items per page:</span>
          <select
            class={cn('pag12', p.class?.sizeChanger)}
            disabled={p.disabled}
            value={pageSize()}
            onChange={e => changePageSize(Number(e.currentTarget.value))}
          >
            <For each={p.pageSizeOptions}>{opt => <option value={opt}>{opt}</option>}</For>
          </select>
          <div class="bg-c3/50 w-px self-stretch"></div>
          <span class={cn('pag23', p.class?.fullyRange)}>
            {range()[0]}–{range()[1]} of {p.total ?? 0} items
          </span>
        </div>

        {/* Right: page input + prev/next buttons */}
        <div class={cn('pag21', p.class?.fullyRight)}>
          <input
            class={cn('pag25', p.class?.fullyPageInput)}
            type="number"
            min={1}
            max={totalPages()}
            value={modernPageInput()}
            disabled={p.disabled}
            style={{ width: `${Math.max(2, modernPageInput().length) + 0.5}ch` }}
            onFocus={e => e.currentTarget.select()}
            onInput={e => setModernPageInput(e.currentTarget.value)}
            onBlur={e => commitPageInput(e.currentTarget.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') {
                commitPageInput((e.currentTarget as HTMLInputElement).value);
                e.currentTarget.blur();
              }
            }}
          />
          <span class={cn('pag24', p.class?.fullyPages)}>of {totalPages()} pages</span>
          <button
            class={cn(
              'pag06',
              p.class?.btn,
              p.class?.prev,
              current() <= 1 && 'pag07',
              current() <= 1 && p.class?.btnDisabled,
            )}
            disabled={p.disabled || current() <= 1}
            onClick={() => changePage(current() - 1)}
            title="Previous Page"
          >
            <ChevronLeft size={16} />
          </button>
          <button
            class={cn(
              'pag06',
              p.class?.btn,
              p.class?.next,
              current() >= totalPages() && 'pag07',
              current() >= totalPages() && p.class?.btnDisabled,
            )}
            disabled={p.disabled || current() >= totalPages()}
            onClick={() => changePage(current() + 1)}
            title="Next Page"
          >
            <ChevronRight size={16} />
          </button>
        </div>
      </div>
    </Show>
  );
};

// ─── Public component ────────────────────────────────────────────────────────

export const Pagination: Component<PaginationProps> = p => {
  return (
    <Switch fallback={<PaginationDefault {...(p as PaginationDefaultProps)} />}>
      <Match when={p.mode === 'simple'}>
        <PaginationSimple {...(p as PaginationSimpleProps)} />
      </Match>
      <Match when={p.mode === 'fully'}>
        <PaginationFully {...(p as PaginationFullyProps)} />
      </Match>
    </Switch>
  );
};
